import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office - Quote", () => {
  // --- Base premiums (simplest cases) ---
  it.todo("empty item list → premium 5 G (only processing fee)");
  it.todo("single plain sword → premium 115 G (100 + 10 first-insurance + 5 fee)");
  it.todo("single plain amulet → premium 71 G (60 + 6 first-insurance + 5 fee)");
  it.todo("single plain staff → premium 93 G (80 + 8 first-insurance + 5 fee)");
  it.todo("single plain potion → premium 49 G (40 + 4 first-insurance + 5 fee)");

  // --- Component blocks ---
  it.todo("2 runes → base premium 50 G");
  it.todo("3 runes → base premium 60 G (block discount applies)");
  it.todo("4 runes → base premium 100 G (no block)");
  it.todo("7 runes → base premium 175 G");
  it.todo("2 runes + 1 moonstone → base premium 75 G (different types, no block)");
  it.todo("3 runes + 3 moonstones → base premium 120 G (two separate blocks)");

  // --- Item-specific modifiers ---
  it.todo("cursed sword → premium 165 G (100 base + 50 curse + 10 first + 5 fee)");
  it.todo("enchantment 5 sword → premium 145 G (100 base + 30 high-enchant + 10 first + 5 fee)");
  it.todo("enchantment 4 sword → premium 115 G (no high-enchantment surcharge)");
  it.todo("cursed enchantment 5 sword → premium 195 G (100 + 50 + 30 + 10 + 5)");

  // --- Policy-wide modifiers ---
  it.todo("loyalty discount at exactly 2 years → premium 63 G on plain amulet (60 - 12 + 10 + 5)");
  it.todo("first insurance surcharge on fresh customer → premium 115 G on plain sword");
  it.todo("follow-up contract discount → deducts 15% from policy total");

  // --- Modifier scope ---
  it.todo("cursed sword + plain amulet → policy base 160 G, cursed adds 50 G (50% of sword only), total before fee 210 G");

  // --- Integration examples ---
  it.todo("newcomer with cursed sword → premium 165 G");
  it.todo("long-standing customer (3y) second contract, cursed enchantment 7 sword → premium 160 G");

  // --- Rounding ---
  it.todo("premium 197.5 G → rounds up to 198 G");
});

describe("MHPCO Claim Office - Claim", () => {
  // --- Standard reimbursement ---
  it.todo("steel sword enchantment 3, damage 500 G → payout 400 G (full - 100 deductible)");
  it.todo("rune damage 200 G → payout 100 G (full - 100 deductible)");

  // --- Special clauses ---
  it.todo("dragon-material sword enchantment 8, damage 1000 G → payout 400 G (50% rule then deductible)");
  it.todo("dragon-material sword enchantment 9, damage 1000 G → payout 400 G (50% wins over full)");
  it.todo("dragon-material sword enchantment 5, damage 800 G → payout 700 G (dragon only, full - deductible)");
  it.todo("steel sword enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");

  // --- Deductible ---
  it.todo("dragon attack: sword 500 + amulet 300 → payout 600 G (deductible per item)");

  // --- Multiple items ---
  it.todo("two swords insured → insurance sum 2000 G, cap 4000 G");

  // --- Cap exhaustion ---
  it.todo("sword cap 2000 G, first claim 1500 G → payout 1400 G, remaining 600 G");
  it.todo("sword cap 2000 G, second claim 1500 G → payout 600 G, remaining 0 G");
  it.todo("cursed sword → cap 2000 G based on unmodified insurance value");
  it.todo("sword + 3 runes → insurance sum 1750 G (block discount affects premium only)");

  // --- Rounding ---
  it.todo("payout 350.5 G → rounds down to 350 G");
});

describe("MHPCO Claim Office - Errors", () => {
  it.todo("quote with unknown item type → throws error");
  it.todo("claim with unknown item type in damages → throws error");
  it.todo("claim with damage amount < 0 → throws error");
  it.todo("claim damages item not in policy → throws error");
  it.todo("more damage entries of a type than policy covers → throws error");
});

export function processScenario(_input: unknown): unknown {
  throw new Error("Not implemented");
}

