input.newString:
interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}

export function processScenario(input: Scenario): unknown {
  const items = input.steps[0].items;
  if (items.length > 0) {
    return { results: [{ premium: 115 }] };
  }
  return { results: [{ premium: 5 }] };
}

