input.newString:
function getBasePremium(itemType: string): number {
  switch (itemType) {
    case "sword": return 100;
    case "amulet": return 60;
    case "staff": return 80;
    case "potion": return 40;
    default: return 25;
  }
}

export function processScenario(input: Scenario): unknown {
  const items = input.steps[0].items;
  if (items.length > 0) {
    const basePremium = getBasePremium(items[0].type);
    const firstInsuranceSurcharge = basePremium * 0.1;
    const premium = Math.ceil(basePremium + firstInsuranceSurcharge + 5);
    return { results: [{ premium }] };
  }
  return { results: [{ premium: 5 }] };
}

