interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}

function getBasePremium(itemType: string): number {
  switch (itemType) {
    case "sword": return 100;

input.oldString:
export function processScenario(input: Scenario): unknown {
  const items = input.steps[0].items;
  if (items.length > 0) {
    const basePremium = calculateBasePremium(items);
    const firstInsuranceSurcharge = basePremium * 0.1;
    const premium = Math.ceil(basePremium + firstInsuranceSurcharge + 5);
    return { results: [{ premium }] };
  }
  return { results: [{ premium: 5 }] };
}

input.newString:
function calculateItemPremium(item: Item): number {
  const base = getBasePremium(item.type);
  let modified = base;
  if (item.cursed) {
    modified += base * 0.5;
  }
  if (item.enchantment !== undefined && item.enchantment >= 5) {
    modified += base * 0.3;
  }
  return modified;
}

export function processScenario(input: Scenario): unknown {
  const items = input.steps[0].items;
  if (items.length > 0) {
    const policyBasePremium = calculateBasePremium(items);
    const itemPremiums = items.reduce((sum, item) => sum + calculateItemPremium(item), 0);
    const firstInsuranceSurcharge = policyBasePremium * 0.1;
    const premium = Math.ceil(itemPremiums + firstInsuranceSurcharge + 5);
    return { results: [{ premium }] };
  }
  return { results: [{ premium: 5 }] };
}

