input.oldString:
function calculateItemPremium(item: Item): number {
  const base = getBasePremium(item.type);
  let modified = base;
  if (item.cursed) {
    modified += base * 0.5;
  }
  if (item.enchantment !== undefined && item.enchantment >= 5) {
    modified += base * 0.3;
  }
  return modified;
}

export function processScenario(input: Scenario): unknown {
  const items = input.steps[0].items;
  if (items.length > 0) {
    const policyBasePremium = calculateBasePremium(items);
    const itemPremiums = items.reduce((sum, item) => sum + calculateItemPremium(item), 0);
    const firstInsuranceSurcharge = policyBasePremium * 0.1;
    const premium = Math.ceil(itemPremiums + firstInsuranceSurcharge + 5);
    return { results: [{ premium }] };
  }
  return { results: [{ premium: 5 }] };
}

input.newString:
function isMainItem(itemType: string): boolean {
  return ["sword", "amulet", "staff", "potion"].includes(itemType);
}

function calculateItemModifiers(items: Item[]): number {
  let modifierSum = 0;
  for (const item of items) {
    if (!isMainItem(item.type)) continue;
    const base = getBasePremium(item.type);
    if (item.cursed) {
      modifierSum += base * 0.5;
    }
    if (item.enchantment !== undefined && item.enchantment >= 5) {
      modifierSum += base * 0.3;
    }
  }
  return modifierSum;
}

export function processScenario(input: Scenario): unknown {
  const items = input.steps[0].items;
  if (items.length > 0) {
    const policyBasePremium = calculateBasePremium(items);
    const itemModifierSum = calculateItemModifiers(items);
    const firstInsuranceSurcharge = policyBasePremium * 0.1;
    const premium = Math.ceil(policyBasePremium + itemModifierSum + firstInsuranceSurcharge + 5);
    return { results: [{ premium }] };
  }
  return { results: [{ premium: 5 }] };
}

